class Solution:
    def preorderTraversal(self, root: Node) -> List[int]:
        result = []
        if root:
            result.append(root.val)
            if root.left:
                result += self.preorderTraversal(root.left)
            if root.right:
                result += self.preorderTraversal(root.right)
        return result

def main():
