def deserialize(s):
    if not s:
        return None
    s = s.strip('[]()\n')
    if s == 'null':
        return None
    i = 0
    def dfs():
        if i >= len(s):
            return None
        val = s[i]
        i += 1
        if s[i] == '\',':
            i += 1
            left = deserialize(s[i:])
            i += len(s[:i].strip('[],\n')) + 1
        else:
            left = None
        if s[i] == '\',':
            i += 1
            right = deserialize(s[i:])
            i += len(s[:i].strip('[],\n')) + 1
        else:
            right = None
        return Node(int(val), left, right)
    return dfs()

class Node:
    def __init__(self, val, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

