string readString() {
    static string str;
    cin >> str;
    return str;
}

Node* deserialize() {
    string str = readString();
    if (str == 'null') return nullptr;
    int val = stoi(str);
    str = readString();
    if (str == ',') return new Node(val);
    str = readString();
    if (str[0] == '[') {
        str = readString();
        Node* left = deserialize();
        str = readString();
        if (str == ',') {
            str = readString();
            Node* right = deserialize();
            return new Node(val, left, right);
        } else {
            return new Node(val, left);
        }
    } else {
        return new Node(val);
    }
}
